import React, { useState, useEffect } from "react";
import { makeStyles } from "@material-ui/core/styles";
import { differenceInDays, addDays } from "date-fns";
import { Heading } from "@chakra-ui/react";
import { useCustomToast } from "../helpers/useCustomToast";
import clsx from "clsx";
import { Button, Paper, Grid, Icon, TextField } from "@material-ui/core";
import { useRecoilState } from "recoil";
import { siteallowsState, loginLevelState } from "./data/atomdata";
//import { useDailyAllowancesContext } from "../context/dailyallowances_context";
import { useDailyAllows } from "./dailyallows/useDailyAllows";
import { useAddDailyAllows } from "./dailyallows/useAddDailyAllows";
//import { useDailyAllowsDetls } from "./dailyallowsdetls/useDailyAllowsDetls";
import { useAddDailyAllowsDetls } from "./dailyallowsdetls/useAddDailyAllowsDetls";

//const drawerWidth = 240;
//const selectYear = [{ name: "2021" }, { name: "2022" }];
// const selectMonth = [
//   { name: "January" },
//   { name: "February" },
//   { name: "March" },
//   { name: "April" },
//   { name: "May" },
//   { name: "June" },
// ];

const DailyAllowancesAddPeriod = ({ handleDialogClose }) => {
  let date = new Date();
  //let longMonth = date.toLocaleString("en-us", { month: "long" });
  //console.log("date", date, longMonth);
  const classes = useStyles();
  const fixedHeightPaper = clsx(classes.paper, classes.fixedHeight);
  const toast = useCustomToast();
  const { dailyallows, setDailyAllowsId } = useDailyAllows();
  //const { dailyallowsdetls } = useDailyAllowsDetls();
  const addDailyAllows = useAddDailyAllows();
  const addDailyAllowsDetls = useAddDailyAllowsDetls();
  const [input, setInput] = useRecoilState(siteallowsState);
  const [loginLevel, setLoginLevel] = useRecoilState(loginLevelState);
  //const [allowsPeriod, setAllowsPeriod] = useState("");
  //const [alert, setAlert] = useState(false);
  const [error, setError] = useState(false);
  // const { dailyallowances, addDailyAllowance, addDailyAllowsDetl } =
  //   useDailyAllowancesContext();
  // function daysInMonth(month, year) {
  //   return new Date(year, month, 0).getDate();
  // }

  useEffect(() => {
    setInput({
      ...input,
      empid: loginLevel.loginUserId,
      name: loginLevel.loginUser,
      jobbonus: loginLevel.siteallows_fee,
      perdiem: loginLevel.perdiem_fee,
      manager: loginLevel.reporting_to,
      client: "",
    });
    setDailyAllowsId(loginLevel.loginUserId);
  }, []);

  // const periodExists = (data) => {
  //   console.log('add period', data)
  //   return dailyallows.some(function (el) {
  //     return el.period === data && el.empid === loginLevel.loginUserId;
  //   });
  // };

  const periodExists = (data) => {
    var lExist = false;
    const startday = parseInt(data.substring(8, 10));
    const endday = parseInt(data.substring(11, 13));
    const existdata = dailyallows.filter((rec) =>
      rec.period.toLowerCase().match(data.substring(0, 8))
    );
    //console.log("existdata", existdata);
    if (existdata.length > 0) {
      existdata.forEach((rec) => {
        const fromday = parseInt(rec.period.substring(8, 10));
        const today = parseInt(rec.period.substring(11, 13));
        if (startday >= fromday && startday <= today) {
          lExist = true;
        }
        if (endday >= fromday && endday <= today) {
          lExist = true;
        }
      });
    }
    return lExist;
  };

  const buildSiteAllows = () => {
    const period =
      input.fromdate.substring(0, 4) +
      "-" +
      input.fromdate.substring(5, 7) +
      "-" +
      input.fromdate.substring(8, 10) +
      "/" +
      input.todate.substring(8, 10);

    const isExist = periodExists(period);
    //console.log("isexist", isExist);
    if (isExist) {
      toast({
        title: "Site Allowance period is existed!",
        status: "warning",
      });
      // setError(true);
      return null;
    }

    // build siteallowsbatch

    const diffInDays = differenceInDays(
      new Date(input.todate),
      new Date(input.fromdate)
    );

    let amount = 0,
      jobbonus = 0,
      perdiem = 0;
    for (let i = 0; i <= diffInDays; i++) {
      jobbonus = jobbonus + Number(input.jobbonus);
      perdiem = perdiem + Number(input.perdiem);
      amount = amount + Number(input.jobbonus) + Number(input.perdiem);
      const data = addDays(new Date(input.fromdate), i);
      addDailyAllowsDetls({
        empid: loginLevel.loginUserId,
        name: loginLevel.loginUser,
        period: period,
        date: data,
        district: input.district,
        typeoperation: input.typeoperation,
        client: input.client,
        location: input.location,
        jobno: input.jobno,
        crewoperation: input.crewoperation,
        jobbonus: input.jobbonus,
        perdiem: input.perdiem,
        status: "Pending",
      });
    }
    //add daily allowances batch
    addDailyAllows({
      period: period,
      location: input.location,
      manager: input.manager,
      name: loginLevel.loginUser,
      empid: loginLevel.loginUserId,
      status: "Pending",
      no_of_days: diffInDays + 1,
      amount: amount,
      totaljobbonus: jobbonus,
      totalperdiem: perdiem,
      fromdate: input.fromdate,
      todate: input.todate,
    });

    // dailyallowances.push({
    //   period: period,
    //   location: input.location,
    //   manager: input.manager,
    //   name: loginLevel.loginUser,
    //   empid: loginLevel.loginUserId,
    //   status: "Pending",
    //   no_of_days: diffInDays,
    //   amount: amount,
    // });
    handleDialogClose();
  };

  const handleChange = (e) => {
    e.preventDefault();
    const { name, type, value } = e.target;
    const val = type === "number" ? parseFloat(value) : value;
    setInput({ ...input, [name]: val });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const period =
      input.fromdate.substring(0, 4) + "-" + input.fromdate.substring(5, 7);
    setInput({
      ...input,
      period: period,
    });

    buildSiteAllows();
  };

  return (
    <Paper
      className={fixedHeightPaper}
      style={{ backgroundColor: "secondary" }}
    >
      <form onSubmit={(e) => handleSubmit(e)}>
        <Grid
          container
          spacing={0}
          direction="row"
          alignItems="center"
          justify="center"
          style={{ border: "1px solid white" }}
        >
          <Heading as="h2" size="lg" color="blue" p={5}>
            Build Site Allowances
          </Heading>
        </Grid>
        <Grid
          container
          spacing={0}
          direction="row"
          alignItems="center"
          justify="center"
          style={{ border: "1px solid white" }}
        >
          <div>
            <Grid
              item
              sm={12}
              style={{ border: "1px solid white" }}
              align="left"
            >
              {/* <div style={{ display: "flex", flexDirection: "row" }}>
                <TextField
                  label="Year"
                  id="margin-normal"
                  name="year"
                  required
                  defaultValue={input.year}
                  className={classes.textField}
                  onChange={(e) => handleChange(e)}
                  style={{ width: "100%", marginTop: 10, marginLeft: 10 }}
                  error={!!error}
                  helperText={error ? error.message : null}
                  select
                >
                  {selectYear.map((item) => {
                    return <MenuItem value={item.name}>{item.name}</MenuItem>;
                  })}
                </TextField>
                <TextField
                  label="Month"
                  id="margin-normal"
                  name="month"
                  required
                  defaultValue={input.month}
                  style={{ width: "100%", marginTop: 10, marginLeft: 0 }}
                  className={classes.textField}
                  onChange={(e) => handleChange(e)}
                  error={!!error}
                  helperText={error ? error.message : null}
                  select
                >
                  {selectMonth.map((item) => {
                    return <MenuItem value={item.name}>{item.name}</MenuItem>;
                  })}
                </TextField>
              </div> */}
              <div style={{ display: "flex", flexDirection: "row" }}>
                <TextField
                  label="From Date"
                  variant="filled"
                  required
                  style={{ width: "100%" }}
                  name="fromdate"
                  value={input.fromdate}
                  type="date"
                  className={classes.textField}
                  onChange={(e) => handleChange(e)}
                  InputLabelProps={{
                    shrink: true,
                  }}
                ></TextField>
              </div>
              <div style={{ display: "flex", flexDirection: "row" }}>
                <TextField
                  label="To Date"
                  variant="filled"
                  required
                  style={{ width: "100%" }}
                  name="todate"
                  value={input.todate}
                  type="date"
                  className={classes.textField}
                  onChange={(e) => handleChange(e)}
                  InputLabelProps={{
                    shrink: true,
                  }}
                ></TextField>
              </div>
              <div style={{ display: "flex", flexDirection: "row" }}>
                {/* <TextField
                  label="Period"
                  variant="filled"
                  required
                  style={{ width: "100%" }}
                  name="period"
                  value={input.period}
                  className={classes.textField}
                  onChange={(e) => handleChange(e)}
                ></TextField> */}
                {/* <Divider className={classes.divider} /> */}
                <TextField
                  label="Manager"
                  variant="filled"
                  required
                  style={{ width: "100%" }}
                  name="manager"
                  value={input.manager}
                  className={classes.textField}
                  onChange={(e) => handleChange(e)}
                ></TextField>
              </div>
              <div style={{ display: "flex", flexDirection: "row" }}>
                {/* <TextField
                  label="District"
                  variant="filled"
                  //required
                  value={input.district}
                  style={{ width: "100%" }}
                  name="district"
                  className={classes.textField}
                  onChange={(e) => handleChange(e)}
                ></TextField> */}
                <TextField
                  label="Location/Rig"
                  variant="filled"
                  required
                  value={input.location}
                  style={{ width: "100%" }}
                  name="location"
                  className={classes.textField}
                  onChange={(e) => handleChange(e)}
                ></TextField>
              </div>
              <div style={{ display: "flex", flexDirection: "row" }}>
                <TextField
                  label="Operation Type"
                  variant="filled"
                  required
                  value={input.typeoperation}
                  style={{ width: "100%" }}
                  name="typeoperation"
                  className={classes.textField}
                  onChange={(e) => handleChange(e)}
                ></TextField>
              </div>
              <div style={{ display: "flex", flexDirection: "row" }}>
                <TextField
                  label="Client"
                  variant="filled"
                  required
                  value={input.client}
                  style={{ width: "100%" }}
                  name="client"
                  className={classes.textField}
                  onChange={(e) => handleChange(e)}
                ></TextField>
              </div>
              <div style={{ display: "flex", flexDirection: "row" }}>
                <TextField
                  label="Ticket No/Job No"
                  variant="filled"
                  required
                  value={input.jobno}
                  style={{ width: "100%" }}
                  name="jobno"
                  className={classes.textField}
                  onChange={(e) => handleChange(e)}
                ></TextField>
              </div>
              <div style={{ display: "flex", flexDirection: "row" }}>
                <TextField
                  label="Operation Role"
                  variant="filled"
                  required
                  value={input.creqoperation}
                  style={{ width: "100%" }}
                  name="crewoperation"
                  className={classes.textField}
                  onChange={(e) => handleChange(e)}
                ></TextField>
              </div>
              <div style={{ display: "flex", flexDirection: "row" }}>
                <TextField
                  label="Job Bonus"
                  variant="filled"
                  required
                  value={input.jobbonus}
                  style={{ width: "100%" }}
                  name="jobbonus"
                  type="number"
                  className={classes.textField}
                  onChange={(e) => handleChange(e)}
                  InputLabelProps={{
                    shrink: true,
                  }}
                ></TextField>
                <TextField
                  label="Per Diem"
                  variant="filled"
                  required
                  value={input.perdiem}
                  style={{ width: "100%" }}
                  name="perdiem"
                  type="number"
                  className={classes.textField}
                  onChange={(e) => handleChange(e)}
                  InputLabelProps={{
                    shrink: true,
                  }}
                ></TextField>
              </div>
            </Grid>
          </div>
        </Grid>
        <Grid
          container
          spacing={0}
          direction="row"
          alignItems="center"
          justify="center"
          style={{ border: "1px solid white" }}
        >
          <div>
            <Button
              type="submit"
              variant="contained"
              color="primary"
              className={classes.button}
            >
              Build <Icon className={classes.rightIcon}>send</Icon>
            </Button>
          </div>
          <div>
            {error &&
              toast({
                title: "Period already existed!",
                status: "warning",
              })}
          </div>
        </Grid>
      </form>
    </Paper>
  );
};

